function sg(n1: number): string {
  let ma: string = ""
  for (let i: number = n1; i > -1; i--) {
    if (i % 3 == 2) {
      ma = ma + "ai"
    } else if (i % 3 == 1) {
      ma = ma + "taka"
    } else {
      ma = ma + "tta."
    }
  }
  return ma
}

